// 마지막으로 생성된 인스턴스 객체(mutiple 속성이 false 인 경우에만 마지막 엘리먼트를 저장한다)
let lastShowInstance = null;

// 위 / 아래 키를통해, 옵션 이동 시, browser scroll 막은 후, 다시 이전값을 돌려주기위해 사용하는 캐시값
const LAGACYS = {};

class BxSelect {

    constructor(){
        this.$root = BxSelect.$root;
        this.opts = OPTS.select;
    }

    /**
     * 초기화 함수
     *
     * @returns {object} 생성된 인스턴스
     */
    initialize(){

        this.$selects = this.$root.find('bx-select');
        this.elems = [];

        $.each(this.$selects, (i, elem) =>{

            const $customElem = $(elem);

            // 사용자 커스텀 엘리먼트를 파싱한다.
            const $component = _parseCustomElement($customElem);
            const _this = $component.get(0);

            $component.prop('bxrender').call(_this);
            this.elems.push($component.get(0));
        });

        _addDocumentElementEventListener();

        LAGACYS.overflow = $(document.body).css('overflow');

        return this;
    }
}

