/**
 * 사용자 `custom` 태그를 `native` 태그로 대치시킨다.
 *
 * @param {object} [$customElem=$(document.documentElement)] - 사용자 custom 엘리먼트
 *
 * @returns {object} 생성된 $container 엘리먼트
 *
 * @private
 *
 * @memberOf BxSelect
 */
function _parseCustomElement($customElem = $(document.documentElement)){

    if (!_.isElement($customElem.get(0))){
        CONSOLE.prop.throw(BxSelect, '$customElem', 'type');
    }

    // $container 엘리먼트를 생성한다.
    let $container = BASE.appendContainerElement(BxSelect.$root, BxSelect.className);

    // 컴포넌트 엘리먼트를 생성한다.
    let $component = _getComponentElement($customElem);

    // 반환받은 `컴포넌트 엘리먼트`를 `컨테이너 엘리먼트`의 자식으로 추가한다.
    $container.append($component);

    // $customElem 엘리먼트를 생성된 `$container` 엘리먼트로 대치시킨다.
    $customElem.replaceWith($container);

    return $component;
}


/**
 * component 엘리먼트를 반환한다.
 *
 * @param {object} [$customElem=$(document.documentElement)] - 사용자 custom 엘리먼트
 *
 * @returns {object} 생성된 component 엘리먼트
 *
 * @private
 *
 * @memberOf BxSelect
 */
function _getComponentElement($customElem = $(document.documentElement)){

    if (!_.isElement($customElem.get(0))){
        CONSOLE.prop.throw(BxSelect, '$customElem', 'type');
    }

    let selectType = $customElem.attr('type');

    switch (selectType){
        case 'default' :
            return _createSelectElement($customElem);
        default :
            return _createSelectElement($customElem);
    }
}

/**
 * select 엘리먼트를 생성한다.
 *
 * @param {object} [$customElem=$(document.documentElement)] - `custom` 엘리먼트
 *
 * @returns {object} select 엘리먼트 객체
 *
 * @private
 * @memberOf BxSelect
 */
function _createSelectElement($customElem = $(document.documentElement)){

    if (!_.isElement($customElem.get(0))){
        CONSOLE.prop.throw(BxSelect, '$customElem', 'type');
    }

    // `bx-select` 엘리먼트에 할당된 옵션을 반환한다.
    let opts = _createComponentOptions($customElem, OPTS.select);

    let _attr = opts.attr;

    let selectClass = _attr.class ? ' ' + _attr.class : '';

    if (selectClass) delete _attr.class;

    let attr = UTIL.objectToStringAttr(_attr);

    let type = opts.type;
    let shape = opts.shape;
    let icon = opts.icon;
    let label = opts.label;
    let disabled = opts.disabled;
    let multiple = opts.multiple;
    let maxHeight = opts.maxHeight;

    let multipleClassName = multiple ? ' multiple' : '';

    if (type === 'text') type = 'text-type';

    let $selectElem = $(`<div ${attr} data-element-type="${ELEMENT_TYPE.select}" class="${CLASS_NAME.bxSelectWrap}${selectClass}${multipleClassName}"></div>`);

    let selectElem = $selectElem.get(0);

    // 할당된 옵션값을 통해 엘리먼트 프로퍼티를 생성한다.
    _setSelectElementProperties(opts, selectElem);

    // 최초 설정한 label 값을 새로운 프로퍼티로 남겨둔다.
    UTIL.setReadOnlyProperty(selectElem, 'defaultLabel', label);

    let topHtml = [];

    if (!multiple){

        topHtml.push(`<div class="${CLASS_NAME.bxSelectHeader} ${type}">`);
        topHtml.push('<span class="wrap">');

        topHtml.push(`<span class="icon"></span>`);
        topHtml.push(`<a href="#" class="text" onclick="return false;" title="${label}">${label}</a>`);
        topHtml.push('</span>');

        topHtml.push('<i class="bx-ctrl-icon i-15 i-ctrl-down"></i>');
        topHtml.push('</div>');
    }

    topHtml.push(`<div class="${CLASS_NAME.bxSelectList} ${shape}">`);
    // firefox focus 이슈 대응으로 tabindex 사용
    topHtml.push(`<div class="${CLASS_NAME.overflow} ${CLASS_NAME.overflowSelector}" tabindex="-1" style="max-height:${maxHeight}px"></div>`);
    topHtml.push('</div>');

    $selectElem.append(topHtml.join(''));

    _addSelectElementEventListener($selectElem, opts);
    // select 엘리먼트의 아이콘을 설정한다.
    _setIconWithSelectElement($selectElem);

    // 엘리먼트의 disabled 를 설정한다.
    _setDisabled($selectElem);

    UTIL.setReadOnlyProperty(selectElem, 'bxOptGroups', []);
    UTIL.setReadOnlyProperty(selectElem, 'bxOptions', []);

    // 커스텀 엘리먼트의 자식 엘리먼트들
    let $children = $customElem.children();

    let groupNodeName = 'BX-OPTGROUP';
    let optionNodeName = 'BX-OPTION';

    let $overflowElem = $selectElem.find(`.${CLASS_NAME.overflowSelector}`);

    _.map($children, v =>{

        // 자식 엘리먼트
        let $child = $(v);

        // 그룹 엘리먼트일 경우
        if (v.nodeName === groupNodeName){

            let $optGroupElem = _createOptGroupElement($child, $selectElem);

            let $optGroupUlElem = $optGroupElem.children('div');

            let $children = $child.children();

            // group 엘리먼트를 추가한다.
            _addElementItem($selectElem.prop('bxOptGroups'), $optGroupElem.get(0));

            // 생성된 group 컬렉션에 option 컬렉션을 추가한다.
            UTIL.setReadOnlyProperty($optGroupElem.get(0), 'bxOptions', []);

            _.map($children, v =>{

                let $child = $(v);

                // 자식 엘리먼트의 nodeName 이 bx-option 일 경우
                if (v.nodeName === optionNodeName){

                    let $elem = _createOptionElementIntoGroupElement($child, $selectElem);
                    let $optionElem = _addElement($optGroupUlElem, $elem);

                    _addElementItem($optGroupElem.prop('bxOptions'), $optionElem.get(0));
                }
            });

            // group 엘리먼트를 추가한다.
            $overflowElem.append($optGroupElem);

            // 엘리먼트의 selected 를 설정한다.
            _setSelectedWithOptGroupElement($optGroupElem);

            // 엘리먼트의 disabled 를 설정한다.
            _setDisabledWithOptGroupElement($optGroupElem);

            _toggleGroupClassName($selectElem);
        }

        if (v.nodeName === optionNodeName){

            let $elem = _createOptionElementIntoOverFlowElement($child, $selectElem);

            let $optionElem = _addElement($overflowElem, $elem);

            _addElementItem($selectElem.prop('bxOptions'), $optionElem.get(0));

            // 엘리먼트의 disabled 를 설정한다.
            _setSelected($optionElem);

            // 엘리먼트의 disabled 를 설정한다.
            _setDisabled($optionElem);
        }
    });

    // bx-* 패턴으로 할당된 모든 네이티브 이벤트를 바인딩 시킨다.
    UTIL.addAllEventListenerWithProperty($selectElem, opts.events);

    return $selectElem;
}

/**
 * optGroup 엘리먼트를 생성한다.
 *
 * @param {object} [targetObject=null]
 * @param {object} [$selectElem=null] - select 엘리먼트 객체
 *
 * @returns {object} optGroup 엘리먼트 객체
 *
 * @private
 * @memberOf BxSelect
 */
function _createOptGroupElement(targetObject = null, $selectElem = null){

    if (!_.isObject(targetObject)){
        CONSOLE.prop.throw(BxSelect, 'targetObject', 'type');
    }

    if (!_.isElement($selectElem.get(0))){
        CONSOLE.prop.throw(BxSelect, '$selectElem', 'type');
    }

    let opts = _createComponentOptions(targetObject, OPTS.optGroup);

    let label = opts.label;

    let _attr = opts.attr;

    if (!_attr.id) _attr.id = _.uniqueId(prefixId + '_' + 'optGroup_');

    let optGroupClass = _attr.class ? ' ' + _attr.class : '';

    if (optGroupClass) delete _attr.class;

    let attr = UTIL.objectToStringAttr(_attr);

    let multiple = $selectElem.prop('multiple');

    let extendOpts = _.extend(opts, {multiple});

    let html = [];

    html.push(`<div ${attr} data-element-type="${ELEMENT_TYPE.optGroup}" class="${CLASS_NAME.optionGroup}${optGroupClass}">`);
    html.push(`<h3>`);

    if (multiple){
        html.push(`<bx-input type="checkbox" title="${label}"></bx-input>`);
    }

    html.push(`<span class="${CLASS_NAME.optionValue}"></span>`);
    html.push(`</h3>`);
    html.push(`<div></div>`);
    html.push(`</div>`);

    let $elem = $(html.join(''));

    multiple && $elem.bxInput().initialize();

    _setOptGroupElementProperties(opts, $elem.get(0));
    _addOptGroupElementEventListener($elem, extendOpts);

    $elem.prop('selected') && setTimeout(()=>{_setSelected($elem);});
    // 엘리먼트의 label 을 설정한다.
    _setLabel($elem);

    return $elem;
}

/**
 * overFlow 엘리먼트 아래에 option 엘리먼트를 생성한다.
 *
 * @param {object} [targetObject=null]
 * @param {object} [$selectElem=null] - select 엘리먼트 객체
 *
 * @returns {object} option 엘리먼트 객체
 *
 * @private
 * @memberOf BxSelect
 */
function _createOptionElementIntoOverFlowElement(targetObject = null, $selectElem = null){

    if (!_.isObject(targetObject)){
        CONSOLE.prop.throw(BxSelect, 'targetObject', 'type');
    }

    if (!_.isElement($selectElem.get(0))){
        CONSOLE.prop.throw(BxSelect, '$selectElem', 'type');
    }

    let opts = _createComponentOptions(targetObject, OPTS.option);

    let label = opts.label;

    let _attr = opts.attr;

    if (!_attr.id) _attr.id = _.uniqueId(prefixId + '_' + 'option_');

    let optionClass = _attr.class ? ' ' + _attr.class : '';

    if (optionClass) delete _attr.class;

    let attr = UTIL.objectToStringAttr(_attr);

    let multiple = $selectElem.prop('multiple');

    let extendOpts = _.extend(opts, {multiple});

    let html = [];

    html.push(`<div ${attr} data-element-type="${ELEMENT_TYPE.option}" class="${CLASS_NAME.option}${optionClass}">`);

    if (multiple){
        html.push(`<bx-input type="checkbox" title="${label}"></bx-input>`);
    }

    html.push(`<span class="icon"></span>`);

    html.push(`<span>`);

    if (multiple){
        html.push(`<p class="${CLASS_NAME.optionValue}"></p>`);
    }
    else{
        html.push(`<a href="#" onclick="return false;" class="${CLASS_NAME.optionValue}" title="${label}"></a>`);
    }

    html.push(`</span>`);

    html.push(`</div>`);

    let $elem = $(html.join(''));

    multiple && $elem.bxInput().initialize();

    _setOptionElementProperties(opts, $elem.get(0));
    _addOptionElementEventListener($elem, extendOpts, $selectElem);

    // 엘리먼트의 아이콘을 설정한다.
    _setIconWithOptionElement($elem);

    // 엘리먼트의 label 을 설정한다.
    _setLabel($elem);

    return $elem;
}

