/**
 * optGroup 엘리먼트 및 아이템들을 삭제한다.
 *
 * @param {object} [$targetElem=null]
 * @param {array} [targetObject=[]]
 * @param {array} [items=[]]
 *
 * @returns {object} 생성된 인스턴스
 *
 * @private
 * @memberOf BxSelect
 */
function _removeOptGroupElementToItems($targetElem = null, targetObject = [], items = []){

    if (!_.isElement($targetElem.get(0))){
        CONSOLE.prop.throw(BxSelect, '$targetElem', 'type');
    }

    if (!_.isArray(targetObject)){
        CONSOLE.prop.throw(BxSelect, 'targetObject', 'type');
    }

    if (!_.isArray(items)){
        CONSOLE.prop.throw(BxSelect, 'items', 'type');
    }

    _.map(items, v =>{

        let $elem = $targetElem.find(`#${v}`);

        let elementType = $elem.attr('data-element-type');

        if (elementType !== ELEMENT_TYPE.optGroup){
            CONSOLE.prop.warn(BxSelect, MESSAGE.notOptGroupType);
            return;
        }

        _removeElement($targetElem, $elem);

        _removeElementItem(targetObject, $elem.get(0));
    });

    return this;
}

/**
 * option 엘리먼트 및 아이템들을 삭제한다.
 *
 * @param {object} [$targetElem=null]
 * @param {array} [targetObject=[]]
 * @param {array} [items=[]]
 *
 * @returns {object} 생성된 인스턴스
 *
 * @private
 * @memberOf BxSelect
 */
function _removeOptionElementToItems($targetElem = null, targetObject = [], items = []){

    if (!_.isElement($targetElem.get(0))){
        CONSOLE.prop.throw(BxSelect, '$targetElem', 'type');
    }

    if (!_.isArray(targetObject)){
        CONSOLE.prop.throw(BxSelect, 'targetObject', 'type');
    }

    if (!_.isArray(items)){
        CONSOLE.prop.throw(BxSelect, 'items', 'type');
    }

    _.map(items, v =>{

        let $elem = $targetElem.find(`#${v}`);

        let elementType = $elem.attr('data-element-type');

        // 엘리먼트 타입 검사
        if (elementType !== ELEMENT_TYPE.option){
            CONSOLE.prop.warn(BxSelect, MESSAGE.notOptionType);
            return;
        }

        _removeElement($targetElem, $elem);

        _removeElementItem(targetObject, $elem.get(0));
    });

    return this;
}

/**
 * 엘리먼트 및 아이템 업데이트를 위한 함수
 *
 * @param {object} [$targetElem=null]
 * @param {array} [items=[]]
 * @param {function} [callback=[]]
 *
 * @returns {object} 생성된 인스턴스
 *
 * @private
 * @memberOf BxSelect
 */
function _updateElementToItems($targetElem = null, items = [], callback = function (){
}){

    if (!_.isElement($targetElem.get(0))){
        CONSOLE.prop.throw(BxSelect, '$targetElem', 'type');
    }

    if (!_.isArray(items)){
        CONSOLE.prop.throw(BxSelect, 'items', 'type');
    }

    if (!_.isFunction(callback)){
        CONSOLE.prop.throw(BxSelect, 'callback', 'type');
    }

    _.map(items, v =>{

        let $elem = $targetElem.find(`#${v}`);

        callback($targetElem.children('#' + $elem.attr('id')));
    });

    return this;
}

/**
 * show 여부를 반환한다.
 *
 * @returns {object} show 유/무
 *
 * @private
 * @memberOf BxSelect
 */
function _isShow(){

    let $componentElem = $(this);
    let $bxSelectListElem = $componentElem.find(`.${CLASS_NAME.bxSelectList}`);

    return $bxSelectListElem.css('display') === 'block' ? true : false;
}

/**
 * optGroup 엘리먼트를 선택한다.
 *
 * @param {object} [$optGroupElem=null]
 * @param {object} [$optionElem=null]
 *
 * @returns {object} 생성된 인스턴스
 *
 * @private
 * @memberOf BxSelect
 */
function _selectOptGroupElement($optGroupElem = null, $optionElem = null){

    if (!_.isElement($optGroupElem.get(0))){
        CONSOLE.prop.throw(BxSelect, '$optGroupElem', 'type');
    }

    if (!_.isElement($optionElem.get(0))){
        CONSOLE.prop.throw(BxSelect, '$optionElem', 'type');
    }

    let bxOptions = $optGroupElem.prop('bxOptions');
    let selectedLength = _.filter(bxOptions, {selected: true}).length;
    let unSelectedLength = _.filter(bxOptions, {selected: false}).length;
    let optGroupElemSelected = $optGroupElem.prop('selected');

    if (!$optionElem.prop('selected') && bxOptions.length !== unSelectedLength){
        if (optGroupElemSelected === true) $optGroupElem.prop('selected', 'undetermined');
    }

    if (bxOptions.length === selectedLength){
        if (optGroupElemSelected === 'undetermined' || optGroupElemSelected === false) $optGroupElem.prop('selected', true);
    }

    if (bxOptions.length === unSelectedLength){
        if (optGroupElemSelected) $optGroupElem.prop('selected', false);
    }

    return this;
}

/**
 * select 엘리먼트의 아이콘을 설정한다.
 *
 * @param {object} [$selectElem=null]
 *
 * @returns {object} 생성된 인스턴스
 *
 * @private
 * @memberOf BxSelect
 */
function _setIconWithSelectElement($selectElem = null){

    if (!_.isElement($selectElem.get(0))){
        CONSOLE.prop.throw(BxSelect, '$selectElem', 'type');
    }

    let icon = $selectElem.prop('icon');
    let $headerElem = $selectElem.find(`.${CLASS_NAME.bxSelectHeader}`);
    let $iconElem = $headerElem.find(`.${CLASS_NAME.icon}`);

    $headerElem.removeClass('add-icon');
    $iconElem.find('i').remove();

    if (_.trim(icon).length > 0){
        $headerElem.addClass('add-icon');
        $iconElem.append(`<i class="${icon}"></i>`);
    }

    return this;
}

/**
 * option 엘리먼트의 아이콘을 설정한다.
 *
 * @param {object} [$optionElem=null]
 *
 * @returns {object} 생성된 인스턴스
 *
 * @private
 * @memberOf BxSelect
 */
function _setIconWithOptionElement($optionElem = null){

    if (!_.isElement($optionElem.get(0))){
        CONSOLE.prop.throw(BxSelect, '$optionElem', 'type');
    }

    let icon = $optionElem.prop('icon');
    let $iconElem = $optionElem.find(`.${CLASS_NAME.icon}`);

    $iconElem.find('i').remove();

    if (_.trim(icon).length > 0){
        $iconElem.append(`<i class="${icon}"></i>`);
    }

    return this;
}

/**
 * 엘리먼트 label 을 설정한다.
 *
 * @param {object} [$elem=null]
 *
 * @returns {object} 생성된 인스턴스
 *
 * @private
 * @memberOf BxSelect
 */
function _setLabel($elem = null){

    if (!_.isElement($elem.get(0))){
        CONSOLE.prop.throw(BxSelect, '$optionElem', 'type');
    }

    let label = $elem.prop('label');
    let $textElem = $($elem.find(`.${CLASS_NAME.optionValue}`).get(0));

    $textElem.text(label);

    return this;
}

/**
 * select 엘리먼트의 label 및 value 에 기본값을 설정한다.
 *
 * @param {object} [$selectElem=null]
 *
 * @returns {object} 생성된 인스턴스
 *
 * @private
 * @memberOf BxSelect
 */
function _initSelectElement($selectElem = null){

    if (!_.isElement($selectElem.get(0))){
        CONSOLE.prop.throw(BxSelect, '$selectElem', 'type');
    }

    let defaultLabel = $selectElem.prop('defaultLabel');
    let _value = UTIL.convertInternalPropertyName('value');

    // value는 이미 set에 등록 되어 있고 이 함수를 자기 자신이 호출 하고 있다
    // 프로퍼티로 접근시 해당 함수로 무한 반복 하기 때문에 convert 된
    // 이름으로 접근하면 set을 타는것을 방지 할 수 있다.

    $selectElem.prop('label', defaultLabel);
    $selectElem.prop(_value, '');

    return this;
}

/**
 * 커스텀 엘리먼트 아이디를 반환한다.
 *
 * @param {array} [targetArray=[]]
 *
 * @returns {array} 아이디 배열
 *
 * @private
 * @memberOf BxSelect
 */
function _getElementIds(targetArray = []){

    if (!_.isArray(targetArray)){
        CONSOLE.prop.throw(BxSelect, 'targetArray', 'type');
    }

    let ret = [];

    _.map(targetArray, v => ret.push($(v).attr('id')));

    return ret;
}

/**
 * 엘리먼트를 선택한다.
 *
 * @param {object} [$elem=null]
 *
 * @returns {object} 생성된 인스턴스
 *
 * @private
 * @memberOf BxSelect
 */
function _setSelected($elem = null){

    if (!_.isElement($elem.get(0))){
        CONSOLE.prop.throw(BxSelect, '$elem', 'type');
    }

    let $selectElem = $elem.parents(`.${CLASS_NAME.bxSelectWrap}`);
    let multiple = $selectElem.prop('multiple');

    let elementType = $elem.attr('data-element-type');
    let selected = $elem.prop('selected');

    // select 엘리먼트의 multiple 속성이 true 인 경우
    if (multiple){

        let _selected = elementType === ELEMENT_TYPE.optGroup && selected === 'undetermined' ? false : selected;
        let $checkboxElem = $($elem.find('input[type="checkbox"]').get(0));

        const value = $elem.prop('value');

        $checkboxElem.prop('checked', _selected);

        if (_.isUndefined(value)) return;

        if (_selected) {
            $selectElem.prop('value').push(value);
        }
        else {
            const _value = $selectElem.prop('value');
            const idx = _value.indexOf(value);
            if (idx === -1) return;
            _value.splice(idx, 1);
            $selectElem.prop('value', _value);
        }
    }
    else{

        if (selected){

            let text = $elem.text();
            let value = $elem.prop('value');

            $selectElem.prop('label', text);
            $selectElem.prop('value', value);

        }

    }

    if (elementType === ELEMENT_TYPE.optGroup){

        _.map($elem.prop('bxOptions'), elem =>{

            if (selected === true){
                if (!elem.selected) elem.selected = true;
            }
            else if (selected === false){
                if (elem.selected) elem.selected = false;
            }
        });
    }

    return this;
}

/**
 * 모든 옵션 엘리먼트의 선택을 해제한다.
 *
 * @param {object} [$selectElem=null]
 * @param {object} [$optionElem=null]
 *
 * @returns {object} 생성된 인스턴스
 *
 * @private
 *
 * @memberOf BxSelect
 */
function _unSelectAllOptionElement($selectElem = null, $optionElem = null){

    if (!_.isElement($selectElem.get(0))){
        CONSOLE.prop.throw(BxSelect, '$selectElem', 'type');
    }

    if (!_.isElement($optionElem.get(0))){
        CONSOLE.prop.throw(BxSelect, '$optionElem', 'type');
    }

    let selectElem = $selectElem.get(0);
    let optionElem = $optionElem.get(0);

    let selected = $optionElem.prop('selected');

    let bxOptGroups = selectElem['bxOptGroups'];
    let bxOptions = selectElem['bxOptions'];

    _.map(bxOptGroups, (v, k) =>{
        _.map(v['bxOptions'], (vv, kk) =>{
            if (vv !== optionElem){
                if (vv.selected) vv.selected = false;
            }
        });
    });

    _.map(bxOptions, (v, k) =>{
        if (v !== optionElem){
            if (v.selected) v.selected = false;
        }
    });

    return this;
}

/**
 * optGroup 엘리먼트를 선택한다.
 *
 * @param {object} [$elem=null]
 *
 * @returns {object} 생성된 인스턴스
 *
 * @private
 * @memberOf BxSelect
 */
function _setSelectedWithOptGroupElement($elem = null){

    if (!_.isElement($elem.get(0))){
        CONSOLE.prop.throw(BxSelect, '$elem', 'type');
    }

    let elementType = $elem.attr('data-element-type');
    let selected = $elem.prop('selected');

    let _selected = elementType === ELEMENT_TYPE.optGroup && selected === 'undetermined' ? false : selected;

    let $checkboxElem = $($elem.find('input[type="checkbox"]').get(0));

    $checkboxElem.prop('checked', _selected);

    if (elementType === ELEMENT_TYPE.optGroup){

        let bxOptions = $elem.prop('bxOptions');

        _.map(bxOptions, elem =>{

            if (selected === true){
                elem.selected = true;
            }
            else if (selected === false){
                let selected = elem.selected;
                elem.selected = selected;
            }
        });
    }

    return this;
}

/**
 * 엘리먼트를 disabled 한다.
 *
 * @param {object} [$elem=null]
 *
 * @returns {object} 생성된 인스턴스
 *
 * @private
 * @memberOf BxSelect
 */
function _setDisabled($elem = null){

    if (!_.isElement($elem.get(0))){
        CONSOLE.prop.throw(BxSelect, '$elem', 'type');
    }

    let elementType = $elem.attr('data-element-type');
    let disabled = false;

    if (elementType === ELEMENT_TYPE.select){

        disabled = $elem.prop('disabled');

        let label = $elem.prop('label');

        $elem = $elem.find(`.${CLASS_NAME.bxSelectHeader}`);

        let $wrapElem = $elem.find('.wrap');
        $wrapElem.find('a').remove();
        $wrapElem.find('.text').remove();

        if (disabled){
            $wrapElem.append(`<span class="text">${label}</span>`);
        }
        else{
            $wrapElem.append(`<a href="#" class="text" onclick="return false;" title="${label}">${label}</a>`);
        }
    }
    else{
        disabled = $elem.prop('disabled');
    }

    if (disabled) $elem.addClass('disabled');
    else $elem.removeClass('disabled');

    if (elementType === ELEMENT_TYPE.optGroup){

        let $checkedElems = $elem.find('input[type="checkbox"]');
        let $optionElems = $elem.find('div div');

        if ($checkedElems.length) _.map($checkedElems, (v, k) => $(v).attr('disabled', disabled));
        _.map($optionElems, (v, k) => $(v).prop('disabled', disabled));
    }
    else if (elementType === ELEMENT_TYPE.option){

        let $checkedElem = $elem.find('input[type="checkbox"]');
        if ($checkedElem.get(0)) $checkedElem.attr('disabled', disabled);
    }

    return this;
}

/**
 * optGroup 엘리먼트를 disabled 한다.
 *
 * @param {object} [$elem=null]
 *
 * @returns {object} 생성된 인스턴스
 *
 * @private
 * @memberOf BxSelect
 */
function _setDisabledWithOptGroupElement($elem = null){

    if (!_.isElement($elem.get(0))){
        CONSOLE.prop.throw(BxSelect, '$elem', 'type');
    }

    let elementType = $elem.attr('data-element-type');
    let disabled = false;

    if (elementType === ELEMENT_TYPE.select){
        disabled = $elem.prop('disabled');
        $elem = $elem.find(`.${CLASS_NAME.bxSelectHeader}`);
    }
    else{
        disabled = $elem.prop('disabled');
    }

    if (disabled) $elem.addClass('disabled');
    else $elem.removeClass('disabled');

    if (elementType === ELEMENT_TYPE.optGroup){

        let $checkedElems = $elem.find('input[type="checkbox"]');
        let $optionElems = $elem.find('div div');

        if (disabled){

            if ($checkedElems.length) _.map($checkedElems, (v, k) => $(v).attr('disabled', disabled));
            _.map($optionElems, (v, k) => $(v).prop('disabled', disabled));
        }
        else{

            if ($checkedElems.length){

                _.map($checkedElems, (v, k) =>{

                    let $v = $(v);
                    $v.attr('disabled', $v.prop('disabled'));
                });
            }

            _.map($optionElems, (v, k) =>{

                let $v = $(v);
                $v.prop('disabled', $v.prop('disabled'));
            });
        }
    }
    else if (elementType === ELEMENT_TYPE.option){

        let $checkedElem = $elem.find('input[type="checkbox"]');
        if ($checkedElem.get(0)) $checkedElem.attr('disabled', disabled);
    }

    return this;
}

/**
 *
 * 정해진 그룹의 가장 뒤에 새로운 옵션을 추가한다.
 *
 * @param {string} [groupId=''] - 그룹 아이디
 *
 * @param {object|object[]} [optionItems=[]] - 옵션 아이템
 * @param {string} optionItems.label - label
 * @param {string} optionItems.value - value
 * @param {string} optionItems.icon - icon
 * @param {string} optionItems.selected - 엘리먼트의 selected 유/무
 * @param {boolean} [optionItems.disabled=false] - 엘리먼트의 disabled 유/무
 * @param {object} optionItems.attr - attr 객체
 *
 * @returns {object} 생성된 인스턴스
 *
 * @alias addGroupOptions
 *
 * @private
 *
 * @memberOf BxSelect
 */
function _addGroupOptions(groupId = '', optionItems = []){

    if (!_.isString(groupId) || _.trim(groupId).length === 0){
        CONSOLE.prop.throw(BxSelect, 'groupId', 'type');
    }

    if (!_.isPlainObject(optionItems) && !_.isArray(optionItems)){
        CONSOLE.prop.throw(BxSelect, 'optionItems', 'type');
    }

    optionItems = _.isPlainObject(optionItems) ? [optionItems] : optionItems;

    let $selectElem = $(this);
    let $overflowElem = $selectElem.find(`.${CLASS_NAME.overflowSelector}`);

    let $optGroupElem = $overflowElem.find(`#${groupId}`);
    let groupIndex = $overflowElem.find('div[data-element-type="optGroup"]').index($optGroupElem);
    let $optGroupUlElem = $($optGroupElem.children('div').get(0));

    if (groupIndex === -1) return this;

    // 옵션 그룹을 추가한다.
    let bxOptions = this.bxOptGroups[groupIndex].bxOptions;

    _addOptionElementToItems($optGroupUlElem, bxOptions, optionItems);

    this['bxadd'](ELEMENT_TYPE.option, bxOptions);

    return this;
}

