/**
 * 브라우저 스크롤 설정 함수
 *
 * @param hidden
 *
 * @private
 * @memberOf BxSelect
 */
function _setBrowserScroll(hidden = false){

    if (!_.isBoolean(hidden)){
        CONSOLE.prop.throw(BxSelect, 'hidden', 'type');
    }

    let $body = $(document.body);

    if (hidden){
        $body.css('overflow', 'hidden');
    }
    else{
        $body.css('overflow', LAGACYS.overflow);
    }

    return this;
}

